var doc = Rhino.RhinoDoc.ActiveDoc;
var xform = Rhino.Geometry.Transform.Translation(100, 100, 0);
int moved = 0;
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    if (doc.Objects.Transform(obj.Id, xform, true) != Guid.Empty) moved++;
}
doc.Views.Redraw();
return new { moved = moved, dx = 100, dy = 100, dz = 0 };
